using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public class ApiTools(IHttpClientFactory httpClientFactory, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("Get a post by its numeric ID from the REST API.")]
    public async Task<string> GetPost(
        [Description("The numeric ID of the post to retrieve (1-100)")] int postId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching post {PostId}", postId);
        var client = httpClientFactory.CreateClient("api");
        var response = await client.GetAsync($"/posts/{postId}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("List all posts, optionally filtered by user ID.")]
    public async Task<string> ListPosts(
        [Description("Filter posts by this user ID. Pass 0 for no filter.")] int userId = 0,
        CancellationToken cancellationToken = default)
    {
        var client = httpClientFactory.CreateClient("api");
        var url = userId > 0 ? $"/posts?userId={userId}" : "/posts";
        logger.LogInformation("Listing posts from {Url}", url);
        var response = await client.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Create a new post via the REST API.")]
    public async Task<string> CreatePost(
        [Description("Title of the new post")] string title,
        [Description("Body content of the new post")] string body,
        [Description("User ID of the post author")] int userId,
        CancellationToken cancellationToken = default)
    {
        var client = httpClientFactory.CreateClient("api");
        var payload = JsonSerializer.Serialize(new { title, body, userId });
        var content = new StringContent(payload, System.Text.Encoding.UTF8, "application/json");

        logger.LogInformation("Creating post for user {UserId}", userId);
        var response = await client.PostAsync("/posts", content, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

